import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Paths;

public class PathTraversalSecure {
    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input containing path traversal
        String directory = "/home/user/files/"; // Base directory

        String normalizedPath = Paths.get(directory, userInput).normalize().toString();
        if (!normalizedPath.startsWith(directory)) {
            System.out.println("Invalid path specified.");
            return;
        }

        try {
            File file = new File(normalizedPath);
            BufferedReader reader = new BufferedReader(new FileReader(file));

            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            reader.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

